// Discord Python 上線通知
// =========================

msg.headers = {
    "Content-Type": "application/json"
};

msg.url = "https://discord.com/api/webhooks/1507070766271959061/bAa1Pf55ixg0bJmqeoJTQVdPt2ScMyITxYr4ukHof8IfBUC6hCaQqysnqkn8paCXQcjO";

// =========================
// IP
// =========================
let ip = msg.payload?.ip || "未知IP";

// 保存 IP 到持久化全域 context，讓重連/重啟後仍可取用
try {
    global.set(
        "python_ip",
        ip,
        "file"
    );
} catch (e) {
    global.set(
        "python_ip",
        ip
    );
}

// =========================
// Discord Payload
// =========================
msg.payload = {

    username:
        "Cat Health Monitor",

    embeds: [

        {

            title:
                "🟢 Python AI 已上線",

            description:
                `偵測到 Python 推論系統啟動`,

            color:
                65280,

            fields: [

                {
                    name: "Python IP",
                    value: String(ip),
                    inline: false
                }

            ],

            footer: {

                text:
                    new Date()
                        .toLocaleString()

            }

        }

    ]
};

return msg;

let ip = null;
try {
    ip = (msg.payload && msg.payload.ip) ? msg.payload.ip : (global.get("python_ip", "file") || global.get("python_ip") || null);
} catch (e) {
    ip = (msg.payload && msg.payload.ip) ? msg.payload.ip : (global.get("python_ip") || null);
}
if (ip) {
    try {
        global.set("python_ip", ip, "file");
    } catch (e) {
        global.set("python_ip", ip);
    }
}
msg.payload = { ip: ip };
msg.stream_url = ip ? `http://${ip}:5000/stream` : "";
node.warn("python_online received IP: " + (ip || 'null'));
return msg;

let ip = null;
try {
    ip = global.get("python_ip", "file") || global.get("python_ip") || null;
} catch (e) {
    ip = global.get("python_ip") || null;
}
if (!ip) {
    return null;
}
msg.payload = { ip: ip };
msg.stream_url = `http://${ip}:5000/stream`;
return msg;

let data = msg.payload;
if (!data) return null;

if (!data.current)     data.current     = {};
if (!data.today_stats) data.today_stats = {};

let stats = data.today_stats;
stats.walk             = stats.walk             || 0;
stats.walk_time        = stats.walk_time        || 0;
stats.lick             = stats.lick             || 0;
stats.lick_time        = stats.lick_time        || 0;
stats.scratch          = stats.scratch          || 0;
stats.scratch_time     = stats.scratch_time     || 0;
stats.shake            = stats.shake            || 0;
stats.shake_time       = stats.shake_time       || 0;
stats.stop             = stats.stop             || 0;
stats.stop_time        = stats.stop_time        || 0;
stats.not_detected_time = stats.not_detected_time || 0;
stats.active_time      = stats.active_time      || 0;
stats.low_conf         = stats.low_conf         || 0;
stats.low_conf_time     = stats.low_conf_time     || 0;

if (Array.isArray(data.behavior_log)) {
    data.behavior_log = data.behavior_log.map(function(item) {
        return {
            behavior: item.behavior || 'unknown',
            time:     item.time     || '--:--',
            duration: item.duration || 0,
            emoji:    getEmoji(item.behavior)
        };
    });
} else {
    data.behavior_log = [];
}

if (!data.current.emoji)     data.current.emoji     = getEmoji(data.current.behavior);
if (!data.current.timestamp) data.current.timestamp = new Date().toLocaleTimeString();



// 行為開始時間追蹤（供時間軸進行中計時器使用）
let _curBeh = (data.current && data.current.behavior) || null;
let _prevBeh = flow.get('tl_cur_behavior');
let _startMs  = flow.get('tl_start_ms') || Date.now();
if (_curBeh !== _prevBeh) {
    _startMs = Date.now();
    flow.set('tl_cur_behavior', _curBeh);
    flow.set('tl_start_ms', _startMs);
}
if (data.current) data.current.start_epoch_ms = _startMs;

// 今日各行為平均時長（供時間軸風險評估）
data.avg_duration = {};
for (let _b of ['walk','lick','scratch','shake','stop']) {
    let _cnt = stats[_b] || 0;
    let _t   = stats[_b + '_time'] || 0;
    data.avg_duration[_b] = _cnt >= 2 ? Math.round(_t / _cnt * 10) / 10 : 0;
}

msg.payload = data;

// CSV：每 5 分鐘寫一次（與 v2 flow 一致）
let now     = Date.now();
let lastCsv = flow.get('last_csv_write') || 0;
let doCsv   = (now - lastCsv) >= 300000;
if (doCsv) flow.set('last_csv_write', now);

let csvMsg = doCsv ? { payload: {
    timestamp:         (function(){var d=new Date(),p=function(n){return String(n).padStart(2,"0")};return d.getFullYear()+"-"+p(d.getMonth()+1)+"-"+p(d.getDate())+" "+p(d.getHours())+":"+p(d.getMinutes())+":"+p(d.getSeconds());})(),
    walk:              stats.walk,              walk_time:         stats.walk_time,
    lick:              stats.lick,              lick_time:         stats.lick_time,
    scratch:           stats.scratch,           scratch_time:      stats.scratch_time,
    shake:             stats.shake,             shake_time:        stats.shake_time,
    stop:              stats.stop,              stop_time:         stats.stop_time,
    active_time:       stats.active_time,
    low_conf:          stats.low_conf,
    low_conf_time:     stats.low_conf_time,
    not_detected_time: stats.not_detected_time,
    activity_score:    data.activity_score || 0
}} : null;

return [
    msg,
    msg,
    msg,
    msg,
    { payload: data.activity_score || 0 },
    csvMsg,
    msg
];

function getEmoji(behavior) {
    switch (behavior) {
        case 'scratch': return '🐾';
        case 'lick':    return '🧼';
        case 'walk':    return '🚶';
        case 'shake':   return '🔄';
        case 'stop':    return '⏹';
        case 'not':     return '📷';
        default:        return '🐱';
    }
}

let data    = msg.payload;
let stats   = (data && data.today_stats) ? data.today_stats : {};

// ── 讀取用戶設定（與 v2 P4 共用 global context）─────────────
let cfg         = global.get('v2_user_settings','file') || {};
let LICK_THR    = cfg.lick_pct    != null ? +cfg.lick_pct    : 20;
let SCRATCH_THR = cfg.scratch_pct != null ? +cfg.scratch_pct : 15;
let SHAKE_THR   = cfg.shake_pct   != null ? +cfg.shake_pct   : 10;
let STOP_THR    = cfg.stop_pct    != null ? +cfg.stop_pct    : 55;
let LSC_THR     = cfg.lsc_count   != null ? +cfg.lsc_count   : 10;

// ── 基礎時間變數 ──────────────────────────────────────────────
let walk_t    = Number(stats.walk_time    || 0);
let lick_t    = Number(stats.lick_time    || 0);
let scratch_t = Number(stats.scratch_time || 0);
let shake_t   = Number(stats.shake_time   || 0);
let stop_t    = Number(stats.stop_time    || 0);
let td_active = Number(stats.active_time  || 0);

// ── 1. 行為佔比 distribution ──────────────────────────────────
let totalBeh = walk_t + lick_t + scratch_t + shake_t + stop_t;
let dist = totalBeh > 0 ? {
    walk:    parseFloat((walk_t    / totalBeh * 100).toFixed(2)),
    lick:    parseFloat((lick_t    / totalBeh * 100).toFixed(2)),
    scratch: parseFloat((scratch_t / totalBeh * 100).toFixed(2)),
    shake:   parseFloat((shake_t   / totalBeh * 100).toFixed(2)),
    stop:    parseFloat((stop_t    / totalBeh * 100).toFixed(2))
} : {walk:0, lick:0, scratch:0, shake:0, stop:0};
data.distribution = dist;

// ── 2. 節律分析 rhythm（from hourly_distribution in payload）──
let hourly = stats.hourly_distribution || {};
let _pds = {
    '00-06':{walk:0,lick:0,scratch:0,shake:0,stop:0,total:0},
    '06-12':{walk:0,lick:0,scratch:0,shake:0,stop:0,total:0},
    '12-18':{walk:0,lick:0,scratch:0,shake:0,stop:0,total:0},
    '18-24':{walk:0,lick:0,scratch:0,shake:0,stop:0,total:0}
};
for (let h=0; h<24; h++) {
    let k=String(h).padStart(2,'0'), hd=hourly[k]||{};
    let pd=h<6?'00-06':h<12?'06-12':h<18?'12-18':'18-24';
    for (let b of ['walk','lick','scratch','shake','stop']) { _pds[pd][b]+=(hd[b]||0); _pds[pd].total+=(hd[b]||0); }
}
let rhythm = {};
for (let [pd,d] of Object.entries(_pds)) {
    if (d.total===0) { rhythm[pd]={dominant:'none',pct:{},total:0}; continue; }
    let bs=['walk','lick','scratch','shake','stop'];
    let dom=bs.reduce((a,b)=>d[a]>=d[b]?a:b,'stop');
    let pct={}; for (let b of bs) pct[b]=parseFloat((d[b]/d.total*100).toFixed(2));
    rhythm[pd]={dominant:dom, pct, total:parseFloat(d.total.toFixed(1))};
}

// ── 3. 同步寫入 v2 global context（讓 v2 定時任務基線引擎繼續正常運作）──
let _tdDate = new Date().toLocaleDateString('zh-TW');
global.set('v2_today', {
    date: _tdDate,
    walk:{count:stats.walk||0,time:walk_t}, lick:{count:stats.lick||0,time:lick_t},
    scratch:{count:stats.scratch||0,time:scratch_t}, shake:{count:stats.shake||0,time:shake_t},
    stop:{count:stats.stop||0,time:stop_t},
    active_time:stats.active_time||0,
    low_conf:{count:stats.low_conf||0,time:stats.low_conf_time||0},
    not_detected_time:stats.not_detected_time||0, monitoring_seconds:stats.monitoring_seconds||0
}, 'file');
global.set('v2_hourly',            stats.hourly_distribution||{});
global.set('v2_transition_matrix', stats.transition_matrix  ||{});

// ── 4. dScore：行為占比偏離 (0-100) — 不需基線 ───────────────
let dScore = 0;
if (dist.lick    > LICK_THR)    dScore += Math.min(30, (dist.lick    - LICK_THR)    * 1.5);
if (dist.scratch > SCRATCH_THR) dScore += Math.min(35, (dist.scratch - SCRATCH_THR) * 2.0);
if (dist.shake   > SHAKE_THR)   dScore += Math.min(35, (dist.shake   - SHAKE_THR)   * 2.5);
if (dist.stop    > STOP_THR)    dScore += Math.min(20, (dist.stop    - STOP_THR)    * 1.0);
if (dist.walk    < 10 && td_active > 300) dScore += 15;
dScore = Math.min(100, Math.round(dScore));

// ── 5. fScore：頻率偏離（讀取 v2_baseline；無基線時 = 0）────────
let fScore = 0, hasBaseline = false;
try {
    let bl = global.get('v2_baseline', 'file') || global.get('v2_baseline');
    if (bl && bl.metrics) {
        hasBaseline = true;
        let m = bl.metrics;
        let pctDev = function(cur, key) {
            let b = m[key]; if (!b || b.mean === 0) return 0;
            return (cur - b.mean) / b.mean * 100;
        };
        let ld  = pctDev(lick_t,                         'lick_time');
        let sd  = pctDev(scratch_t,                      'scratch_time');
        let shd = pctDev(Number(stats.shake_count || 0), 'shake_count');
        let std = pctDev(stop_t,                         'stop_time');
        if (ld  > 150) fScore += 30; else if (ld  > 100) fScore += 20; else if (ld  >  50) fScore += 10;
        if (sd  > 200) fScore += 35; else if (sd  > 150) fScore += 25; else if (sd  >  80) fScore += 15;
        if (shd > 100) fScore += 35; else if (shd >  50) fScore += 20; else if (shd >  30) fScore += 10;
        if (std >  80) fScore += 20; else if (std >  50) fScore += 10;
        fScore = Math.min(100, Math.round(fScore));
    }
} catch(e) {}

// ── 6. rScore：節律偏離 (0-100) ───────────────────────────────
let rScore = 0;
let night = rhythm['00-06'] || {};
if (night.dominant==='scratch'||night.dominant==='lick') rScore += 30;
if (night.dominant==='shake')                             rScore += 25;
if (night.pct && night.pct.scratch > 20)                 rScore += 20;
let day06 = rhythm['06-12'] || {}, day12 = rhythm['12-18'] || {};
if (day06.pct && day12.pct && (day06.pct.walk||0)<15 && (day12.pct.walk||0)<15 && dist.walk<20) rScore += 20;
rScore = Math.min(100, rScore);

// ── 7. tScore：轉移偏離 (0-100) ───────────────────────────────
let mx = stats.transition_matrix || {};
let tScore = 0;
let lsc  = (mx['lick->scratch']||0) + (mx['scratch->lick']||0);
let shch = mx['shake->shake'] || 0;
let stst = mx['stop->stop']   || 0;
if (lsc>LSC_THR*2) tScore+=40; else if(lsc>LSC_THR) tScore+=20; else if(lsc>Math.max(2,Math.round(LSC_THR/2))) tScore+=10;
if (shch>15) tScore+=30; else if(shch>8) tScore+=15;
if (stst>50) tScore+=20; else if(stst>30) tScore+=10;
tScore = Math.min(100, tScore);

// ── 8. 綜合風險分（四維加權：占比30% 頻率35% 節律20% 轉移15%）──
let riskScore = Math.round(dScore*0.30 + fScore*0.35 + rScore*0.20 + tScore*0.15);
riskScore = Math.max(0, Math.min(100, riskScore));

let level, color, emoji;
if      (riskScore < 20) { level='Normal';    color='#4caf50'; emoji='✅'; }
else if (riskScore < 45) { level='Attention'; color='#ffa726'; emoji='⚠️'; }
else if (riskScore < 70) { level='Warning';   color='#ff7043'; emoji='🚨'; }
else                      { level='High Risk'; color='#f44336'; emoji='🆘'; }

// ── 警示列表 ──────────────────────────────────────────────────
let alerts = [];
if (dist.lick    > LICK_THR)    alerts.push({type:'lick',       msg:'舔舐佔比 ' + dist.lick.toFixed(1)    + '%，超過閾值 ' + LICK_THR    + '%'});
if (dist.scratch > SCRATCH_THR) alerts.push({type:'scratch',    msg:'搔抓佔比 ' + dist.scratch.toFixed(1) + '%，超過閾值 ' + SCRATCH_THR + '%'});
if (dist.shake   > SHAKE_THR)   alerts.push({type:'shake',      msg:'甩頭佔比 ' + dist.shake.toFixed(1)   + '%，超過閾值 ' + SHAKE_THR   + '%'});
if (dist.stop    > STOP_THR)    alerts.push({type:'inactivity', msg:'靜止佔比 ' + dist.stop.toFixed(1)    + '%，活動力偏低'});
if (lsc > LSC_THR) {
    let ls=mx['lick->scratch']||0, sl=mx['scratch->lick']||0, half=Math.max(2,Math.round(LSC_THR/2));
    let transMsg=(ls>half&&sl>half)?'lick↔scratch 循環 '+lsc+' 次，疑似皮膚不適':sl>ls?'scratch→lick '+sl+' 次（搔後舔舐），疑似皮膚不適':'lick→scratch '+ls+' 次（舔後搔抓），疑似皮膚不適';
    alerts.push({type:'transition', msg:transMsg});
}
if (hasBaseline && fScore >= 20) alerts.push({type:'dev', msg:'行為頻率與個體基線偏離（fScore: ' + fScore + '）'});

data.risk = {
    score: riskScore, level, color, emoji,
    components: { distribution:dScore, frequency:fScore, rhythm:rScore, transition:tScore },
    alerts,
    computed_at: (function(){ let d=new Date(),p=function(n){return String(n).padStart(2,'0')}; return d.getFullYear()+'-'+p(d.getMonth()+1)+'-'+p(d.getDate())+' '+p(d.getHours())+':'+p(d.getMinutes())+':'+p(d.getSeconds()); })()
};
data.alerts = alerts;
global.set('v2_risk', data.risk);
flow.set('v2_today_risk', {level, score: riskScore});
return msg;

let risk   = msg.payload.risk   || {};
let alerts = msg.payload.alerts || [];

if (!risk.level || risk.level === 'Normal') {
    flow.set("last_discord_alert", "");
    return null;
}

let dedup_key = risk.level + '|' + alerts.map(function(a){ return a.type||''; }).join(',');
let last_key  = flow.get("last_discord_alert") || "";
if (last_key === dedup_key) return null;
flow.set("last_discord_alert", dedup_key);

let colorMap = { Attention: 16753920, Warning: 16729344, 'High Risk': 16711680 };
let embed_color = colorMap[risk.level] || 16711680;

let fields = [
    { name: '🎯 Risk Score', value: String(risk.score) + '/100', inline: true },
    { name: '📊 風險等級',   value: (risk.emoji||'') + ' ' + risk.level, inline: true }
];
if (risk.components) {
    fields.push({ name: '📊 占比偏離', value: String(risk.components.distribution||0), inline: true });
    if ((risk.components.frequency||0) > 0) {
        fields.push({ name: '📉 頻率偏離', value: String(risk.components.frequency||0), inline: true });
    }
}
if (alerts.length > 0) {
    fields.push({ name: '⚠️ 異常項目', value: alerts.map(function(a){ return a.msg; }).join('\n'), inline: false });
}

msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    username: 'Cat Health Monitor',
    embeds: [{
        title:       (risk.emoji||'🚨') + ' 健康預警：' + risk.level,
        description: '貓咪行為風險分析結果',
        color:       embed_color,
        fields:      fields,
        footer:      { text: new Date().toLocaleString('zh-TW') }
    }]
};
let _cfg = {};
try { _cfg = global.get('v2_user_settings','file') || {}; } catch(e) { _cfg = global.get('v2_user_settings') || {}; }
let _url = (_cfg.discord_webhook || '').trim();
if (!_url) { node.warn('健康預警 Discord：webhook URL 未設定，請在 P4 設定面板填入'); return null; }
msg.url = _url;
return msg;

// fs loaded via node libs: {"var":"fs","module":"fs"}
const TRACKER_PATH = 'C:\\a\\tracker_state.json';

let data = msg.payload;
if (!data || !data.current) return null;

let curBeh = data.current.behavior;
if (!curBeh || curBeh === 'not') return null;

// ── Read tracker_state.json (authoritative daily totals) ──────────
let tracker = {};
try {
    tracker = JSON.parse(fs.readFileSync(TRACKER_PATH, 'utf8'));
} catch(e) {
    node.warn('tracker_state.json: ' + e.message);
}

// ── Date helpers ─────────────────────────────────────────────────
function pad(n){ return String(n).padStart(2,'0'); }
function fmtTime(d){
    return d.getFullYear()+'-'+pad(d.getMonth()+1)+'-'+pad(d.getDate())+
           ' '+pad(d.getHours())+':'+pad(d.getMinutes())+':'+pad(d.getSeconds());
}
let now      = new Date();
let nowMs    = now.getTime();
let nowStr   = fmtTime(now);
let todayStr = now.getFullYear()+'-'+pad(now.getMonth()+1)+'-'+pad(now.getDate());
let isToday  = (tracker.date === todayStr);

// Derive start_time from Python's end_time (HH:MM:SS) and duration (sec)
function deriveStart(endHMS, durSec) {
    let pts = (endHMS||'00:00:00').split(':').map(Number);
    let endSec   = (pts[0]||0)*3600 + (pts[1]||0)*60 + (pts[2]||0);
    let startSec = Math.max(0, endSec - Math.round(durSec));
    return todayStr+' '+pad(Math.floor(startSec/3600))+':'+
           pad(Math.floor((startSec%3600)/60))+':'+pad(startSec%60);
}

// ── Accumulate Python's behavior_log (deduplicate by time+beh+dur) ─
let sessionEvents = flow.get('evt_session') || [];
let sessionKeys   = new Set(flow.get('evt_keys') || []);
let sessionDate   = flow.get('evt_date') || '';

if (sessionDate && sessionDate !== todayStr) {
    sessionEvents = [];
    sessionKeys   = new Set();
}
flow.set('evt_date', todayStr);

let inLog   = data.behavior_log || [];
let changed = false;
for (let i = 0; i < inLog.length; i++) {
    let rec = inLog[i];
    if (!rec || !rec.behavior || rec.behavior === 'not' || !rec.time) continue;
    let dur = Math.max(1, Math.round(rec.duration || 1));
    let key = rec.time + '|' + rec.behavior + '|' + dur;
    if (sessionKeys.has(key)) continue;
    sessionKeys.add(key);
    let nextId = sessionEvents.length > 0 ? sessionEvents[sessionEvents.length-1].event_id + 1 : 1;
    sessionEvents.push({
        event_id:   nextId,
        behavior:   rec.behavior,
        end_time:   todayStr + ' ' + rec.time,
        start_time: deriveStart(rec.time, rec.duration || 0),
        duration:   dur
    });
    changed = true;
}
if (changed) {
    if (sessionEvents.length > 500) {
        // trim oldest keys too
        let trimmed = sessionEvents.slice(-500);
        let keptKeys = new Set(trimmed.map(function(e){
            return e.end_time.slice(11,19)+'|'+e.behavior+'|'+e.duration;
        }));
        sessionKeys = keptKeys;
        sessionEvents = trimmed;
    }
    flow.set('evt_session', sessionEvents);
    flow.set('evt_keys', Array.from(sessionKeys));
}

// ── Merge adjacent same-behavior events (Python sends ~2s segments) ─
// Adjacent = gap ≤ 2s between end_time of one and start_time of the next
function _tsec(dt) {
    var t = dt.slice(11,19).split(':').map(Number);
    return t[0]*3600 + t[1]*60 + t[2];
}
let mergedEvents = (function(evts) {
    if (evts.length < 2) return evts.slice();
    var res = [{ event_id:evts[0].event_id, behavior:evts[0].behavior,
                 start_time:evts[0].start_time, end_time:evts[0].end_time,
                 duration:evts[0].duration }];
    for (var i = 1; i < evts.length; i++) {
        var prev = res[res.length-1], cur = evts[i];
        if (prev.behavior === cur.behavior &&
            _tsec(cur.start_time) - _tsec(prev.end_time) <= 2) {
            prev.end_time = cur.end_time;
            prev.duration = _tsec(cur.end_time) - _tsec(prev.start_time);
        } else {
            res.push({ event_id:cur.event_id, behavior:cur.behavior,
                       start_time:cur.start_time, end_time:cur.end_time,
                       duration:cur.duration });
        }
    }
    return res;
})(sessionEvents);

// ── Current event live timer (Node-RED side) ──────────────────────
let currentEvt = flow.get('evt_cur') || null;
if (!currentEvt || currentEvt.behavior !== curBeh) {
    currentEvt = { behavior: curBeh, start_time: nowStr, start_ms: nowMs };
}
if (!currentEvt.start_ms) currentEvt.start_ms = nowMs;
currentEvt.duration_running = Math.max(0, Math.round((nowMs - currentEvt.start_ms) / 1000));
flow.set('evt_cur', currentEvt);

// ── Per-behavior stats: tracker_state.json for count/total/avg ────
// IQR / mode / max / min derived from accumulated session events
let bCount = (isToday && tracker.behavior_count) ? tracker.behavior_count : {};
let bTime  = (isToday && tracker.behavior_time)  ? tracker.behavior_time  : {};

// 優先用 HTTP payload（每 2s 更新），避免等 30s 存檔才反映
let _statsMinMax = (data.today_stats) || {};
let minDur = _statsMinMax.behavior_min_duration
             || ((isToday && tracker.behavior_min_duration) ? tracker.behavior_min_duration : {});
let maxDur = _statsMinMax.behavior_max_duration
             || ((isToday && tracker.behavior_max_duration) ? tracker.behavior_max_duration : {});

let stats = {};
['walk','lick','scratch','shake','stop'].forEach(function(b) {
    let count  = Math.round(bCount[b] || 0);
    let totSec = bTime[b] || 0;
    if (count === 0) {
        stats[b] = { count:0, total_duration:0, avg_duration:0,
                     max_duration:0, min_duration:0,
                     mode_duration:null, mode_count:0,
                     outlier_high:null, outlier_low:null };
        return;
    }
    let durs = mergedEvents
        .filter(function(e){ return e.behavior === b; })
        .map(function(e){ return e.duration; });

    let outlierHigh = null, outlierLow = null;
    if (durs.length >= 5) {
        let sorted = durs.slice().sort(function(a,b){ return a-b; });
        let n  = sorted.length;
        let q1 = sorted[Math.floor(n * 0.25)];
        let q3 = sorted[Math.floor(n * 0.75)];
        let iqr = q3 - q1;
        if (iqr > 0) {
            outlierHigh = Math.round(q3 + 1.5 * iqr);
            outlierLow  = Math.max(1, Math.round(q1 - 1.5 * iqr));
        }
    }
    let modeKey = null, modeCnt = 0;
    if (durs.length >= 2) {
        let buckets = {};
        durs.forEach(function(d){
            buckets[d] = (buckets[d]||0) + 1;
        });
        Object.keys(buckets).forEach(function(k){
            if (buckets[k] > modeCnt) { modeCnt = buckets[k]; modeKey = Number(k); }
        });
    }
    stats[b] = {
        count:         count,
        total_duration: Math.round(totSec),
        avg_duration:   Math.round(totSec / count * 10) / 10,
        max_duration:   maxDur[b] != null ? Math.max(1, Math.round(maxDur[b])) : (durs.length > 0 ? Math.max.apply(null, durs) : 0),
        min_duration:   minDur[b] != null ? Math.max(1, Math.round(minDur[b])) : (durs.length > 0 ? Math.min.apply(null, durs) : 0),
        mode_duration:  modeCnt >= 2 ? modeKey : null,
        mode_count:     modeCnt >= 2 ? modeCnt : 0,
        outlier_high:   outlierHigh,
        outlier_low:    outlierLow
    };
});

// ── Per-behavior event arrays with outlier flag ───────────────────
let byBehavior = {};
['walk','lick','scratch','shake','stop'].forEach(function(b) {
    let s = stats[b];
    byBehavior[b] = mergedEvents
        .filter(function(e){ return e.behavior === b; })
        .slice(-20).reverse()
        .map(function(ev) {
            let outlier = null;
            if (s.outlier_high !== null && ev.duration > s.outlier_high) outlier = 'high';
            else if (s.outlier_low !== null && ev.duration < s.outlier_low) outlier = 'low';
            return { event_id:ev.event_id, behavior:ev.behavior,
                     start_time:ev.start_time, end_time:ev.end_time,
                     duration:ev.duration, outlier:outlier };
        });
});

let todayTotal = Object.values(bCount).reduce(function(a,v){ return a+Math.round(v||0); }, 0);

msg.payload = {
    current_event: {
        behavior:         currentEvt.behavior,
        start_time:       currentEvt.start_time,
        duration_running: currentEvt.duration_running,
        status:           'running'
    },
    event_table:       mergedEvents.slice(-20).reverse(),
    event_by_behavior: byBehavior,
    event_stats:       stats,
    total_events:      todayTotal
};
return msg;
